import 'package:flutter/material.dart';import '../widgets/auth_background.dart';import '../widgets/auth_card.dart';import '../widgets/auth_header.dart';import '../widgets/auth_text_field.dart';import '../widgets/primary_button.dart';import '../../../core/constants/app_colors.dart';import '../../../core/routes/app_routes.dart';class RegisterScreen extends StatefulWidget {  const RegisterScreen({super.key});  @override  State<RegisterScreen> createState() => _RegisterScreenState();}class _RegisterScreenState extends State<RegisterScreen> {  final _formKey = GlobalKey<FormState>();  bool _obscure = true;  bool _confirmObscure = true;  bool _loading = false;  void _submit() {    if (!_formKey.currentState!.validate()) return;    setState(() => _loading = true);    Future.delayed(const Duration(seconds: 2), () {      if (mounted) {        setState(() => _loading = false);        ScaffoldMessenger.of(context).showSnackBar(          SnackBar(            content: const Text('Account created successfully!'),            backgroundColor: AppColors.maroon400,            behavior: SnackBarBehavior.floating,            shape: RoundedRectangleBorder(              borderRadius: BorderRadius.circular(10),            ),          ),        );        Navigator.pushReplacementNamed(context, AppRoutes.home);      }    });  }  @override  Widget build(BuildContext context) {    return Scaffold(      body: AuthBackground(        child: SingleChildScrollView(          padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 40),          child: AuthCard(            child: Form(              key: _formKey,              child: Column(                mainAxisSize: MainAxisSize.min,                children: [                  const AuthHeader(                    title: 'Create Account',                    subtitle: 'Join the Tunda system',                  ),                  Padding(                    padding: const EdgeInsets.all(32),                    child: Column(                    