                           : Icons.visibility_outlined,                              size: 20,                              color: AppColors.gray400,                            ),                            onPressed: () => setState(                              () => _confirmObscure = !_confirmObscure,                            ),                          ),                        ),                        const SizedBox(height: 24),                        PrimaryButton(                          label: 'Create Account',                          icon: Icons.person_add_outlined,                          loading: _loading,                          onPressed: _submit,                        ),                        const SizedBox(height: 24),                        Row(                          children: const [                            Expanded(                              child: Divider(color: AppColors.gray200),                            ),                            Padding(                              padding: EdgeInsets.symmetric(horizontal: 12),                              child: Text(                                'or',                                style: TextStyle(                                  color: AppColors.gray400,                                  fontSize: 13,                                ),                              ),                            ),                            Expanded(                              child: Divider(color: AppColors.gray200),                            ),                          ],                        ),                        const SizedBox(height: 16),                        Center(                          child: Row(                            mainAxisSize: MainAxisSize.min,                            children: [                              const Text(                                'Already have an account? ',                                style: TextStyle(                                  fontSize: 14,                                  color: AppColors.gray500,                                ),                              ),                              GestureDetector(                                onTap: () => Navigator.pushNamed(                                  context,                                  AppRoutes.login,                                ),                                child: const Text(                                  'Sign in',                                  style: TextStyle(                                    fontSize: 14,                                    fontWeight: FontWeight.w700,                                    color: AppColors.maroon400,                                  ),                                ),                              ),                            ],                          ),                        ),                      ],                    ),                  ),                ],              ),            ),          ),        ),      ),    );  }}